simple_types.code:
type Baud_Rate is (Baud1200, Baud2400, Baud4800, Baud9600, Baud14400,
                   Baud19200, Baud28800, Baud38400,
                   …, Baud1M);

tagged_types.code:
type UART_Device (Periph : not null access NRF_SVD.UART.UART_Peripheral)
is
  new HAL.UART.UART_Port with private;

