                     Baud   : Baud_Rate;
                     Parity : Boolean)

procedure Receive
  (This    : in out UART_Device;
   Data    : out UART_Data_8b;
   Status  : out UART_Status;
   Timeout : Natural := 1000)

procedure Receive
  (This    : in out UART_Device;
   Data    : out UART_Data_9b;
   Status  : out UART_Status;
   Timeout : Natural := 1000)

procedure Transmit
  (This    : in out UART_Device;
